// Datos del callback (vienen del nodo Edit Fields1)
const callback = $('Edit Fields1').first().json;

// Todas las filas del Google Sheet
const rows = items.map(item => item.json);

// Normalizamos chat_id del callback
const chatId = String(callback.chat_id).trim();

// Buscar filas pendientes de este usuario
const pendientes = rows.filter(r =>
  String(r.chat_id).trim() === chatId &&
  String(r.estado || '').trim().toLowerCase() === 'pendiente_funcion'
);

// Si no hay ninguna fila pendiente
if (!pendientes.length) {
  return [{
    json: {
      ok: false,
      error: 'No se encontró archivo pendiente para este usuario',
      chat_id: chatId,
      funcion_codigo: callback.funcion_codigo || null,
      total_filas_recibidas: rows.length
    }
  }];
}

// Tomar la última fila pendiente (la más reciente)
const archivo = pendientes[pendientes.length - 1];

// Mapear el código del botón a un nombre bonito
const mapaFunciones = {
  funcion_1: 'Función 1: Evaluación del diseño de la prestación',
  funcion_2: 'Función 2: Control de Calidad y Consistencia de Informes',
  funcion_3: 'Función 3: Identificación de Riesgos y Hallazgos',
  funcion_4: 'Función 4: Trazabilidad y Registro Blockchain'
};

const funcionCodigo = callback.funcion_codigo || '';
const funcionElegida = mapaFunciones[funcionCodigo] || funcionCodigo;

// Devolver lo necesario para Workflow 2
return [{
  json: {
    ok: true,
    chat_id: chatId,
    funcion_codigo: funcionCodigo,
    funcion_elegida: funcionElegida,

    row_number: archivo.row_number,
    file_id: archivo.file_id,
    file_name: archivo.file_name,
    file_extension: archivo.file_extension,
    mime_type: archivo.mime_type,
    estado_actual: archivo.estado,
    fecha: archivo.fecha
  }
}];

const item = items[0];
const json = item.json;

// 1) Intentar extraer texto aunque OCR.space marque error parcial
let texto = '';

if (Array.isArray(json.ParsedResults)) {
  texto = json.ParsedResults
    .map(r => r.ParsedText || '')
    .join('\n');
}

// Limpieza básica
texto = (texto || '')
  .replace(/\r/g, '\n')
  .replace(/\n{3,}/g, '\n\n')
  .replace(/[ \t]{2,}/g, ' ')
  .trim();

// 2) Leer mensaje de error si existe
let mensajeError = '';
if (Array.isArray(json.ErrorMessage) && json.ErrorMessage.length > 0) {
  mensajeError = json.ErrorMessage.join(' | ');
} else if (typeof json.ErrorMessage === 'string') {
  mensajeError = json.ErrorMessage;
}

// 3) Si NO hay texto, sí es error real
if (!texto) {
  return [{
    json: {
      ok: false,
      error: mensajeError || 'OCR no devolvió texto',
      raw: json
    }
  }];
}

// 4) Si sí hay texto, seguimos aunque haya error parcial
const ocrParcial = !!json.IsErroredOnProcessing;

return [{
  json: {
    ok: true,
    tipo_documento: 'pdf',
    contenido_documento: texto,
    fuente_texto: 'ocr',
    ocr_parcial: ocrParcial,
    ocr_mensaje: mensajeError || null,
    paginas_procesadas_limitadas: ocrParcial ? true : false
  }
}];

