const rows = items.map(item => item.json);

// Si no hay filas
if (!rows.length) {
  return [{
    json: {
      ok: false,
      error: 'El CSV no contiene filas',
    }
  }];
}

// --- 1) Lista de palabras clave para detectar columnas útiles ---
const keywords = [
  'entidad',
  'documento',
  'informe',
  'hallazgo',
  'observacion',
  'observación',
  'descripcion',
  'descripción',
  'criterio',
  'causa',
  'efecto',
  'recomendacion',
  'recomendación',
  'riesgo',
  'estado',
  'fecha',
  'periodo',
  'período',
  'monto',
  'importe',
  'area',
  'área',
  'unidad',
  'dependencia',
  'oficina',
  'responsable'
];

// --- 2) Obtener todas las columnas del CSV ---
const allColumns = [...new Set(rows.flatMap(row => Object.keys(row)))];

// --- 3) Detectar columnas relevantes por coincidencia de nombre ---
let selectedColumns = allColumns.filter(col => {
  const c = col.toLowerCase().trim();
  return keywords.some(k => c.includes(k));
});

// Si no detecta nada, nos quedamos con las primeras 8 columnas para no romper el flujo
if (!selectedColumns.length) {
  selectedColumns = allColumns.slice(0, 8);
}

// --- 4) Limitar filas para no reventar tokens ---
const MAX_ROWS = 30;
const limitedRows = rows.slice(0, MAX_ROWS);

// --- 5) Reducir cada fila solo a las columnas seleccionadas ---
const reducedRows = limitedRows.map(row => {
  const obj = {};
  for (const col of selectedColumns) {
    obj[col] = row[col] ?? '';
  }
  return obj;
});

// --- 6) Construir un resumen legible para el agente ---
const resumenFilas = reducedRows.map((row, index) => {
  const partes = Object.entries(row)
    .filter(([_, value]) => value !== null && value !== undefined && String(value).trim() !== '')
    .map(([key, value]) => `${key}: ${String(value).trim()}`);

  return `Fila ${index + 1}: ${partes.join(' | ')}`;
}).join('\n');

// --- 7) Texto final que se mandará al agente ---
const contenidoDocumento = `
Resumen estructurado de archivo CSV
Filas totales del archivo: ${rows.length}
Filas analizadas: ${limitedRows.length}
Columnas detectadas en el archivo: ${allColumns.join(', ')}
Columnas seleccionadas para el análisis: ${selectedColumns.join(', ')}

Contenido resumido:
${resumenFilas}
`.trim();

// --- 8) Devolver un solo item para seguir al agente ---
return [{
  json: {
    ok: true,
    tipo_documento: 'csv',
    filas_totales: rows.length,
    filas_analizadas: limitedRows.length,
    columnas_totales: allColumns,
    columnas_usadas: selectedColumns,
    contenido_documento: contenidoDocumento
  }
}];

return [
  {
    json: {
      chat_id: $json.chat_id,
      file_id: $json.file_id,
      file_name: $json.file_name,
      file_extension: $json.file_extension,
      funcion_elegida: $json.funcion_elegida
    }
  }
];

// ===============================
// 1) TRAER DATOS DEL FLUJO
// ===============================
const entrada = $('mapeo_datos').first().json;

// ===============================
// 2) TRAER RESPUESTA DEL MODELO
// ===============================
const modelo = $('Message a model').first().json;

// ===============================
// 3) EXTRAER EL TEXTO DEL JSON DEL MODELO
// Tu caso real:
// modelo.output[0].content[0].text
// ===============================
let rawText = '';

// Caso principal de tu estructura actual
if (
  Array.isArray(modelo.output) &&
  modelo.output[0] &&
  Array.isArray(modelo.output[0].content) &&
  modelo.output[0].content[0] &&
  typeof modelo.output[0].content[0].text === 'string'
) {
  rawText = modelo.output[0].content[0].text;
}

// Caso alternativo: content en raíz
else if (
  Array.isArray(modelo.content) &&
  modelo.content[0] &&
  typeof modelo.content[0].text === 'string'
) {
  rawText = modelo.content[0].text;
}

// Caso alternativo: output string
else if (typeof modelo.output === 'string') {
  rawText = modelo.output;
}

// Caso alternativo: text string
else if (typeof modelo.text === 'string') {
  rawText = modelo.text;
}

// Si no se encontró texto
if (!rawText || typeof rawText !== 'string') {
  return [
    {
      json: {
        ok: false,
        error: 'No se encontró texto válido en la salida del modelo',
        modelo
      }
    }
  ];
}

// ===============================
// 4) LIMPIAR BLOQUE ```json ... ```
// ===============================
const cleanedText = rawText
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/\s*```$/i, '')
  .trim();

// ===============================
// 5) PARSEAR JSON
// ===============================
let analisis;
try {
  analisis = JSON.parse(cleanedText);
} catch (e) {
  return [
    {
      json: {
        ok: false,
        error: 'La salida del modelo no es JSON válido',
        raw: cleanedText,
        detalle: e.message
      }
    }
  ];
}

// ===============================
// 6) UNIR DATOS DE ENTRADA + IA
// ===============================
return [
  {
    json: {
      ok: true,

      // Datos originales del flujo
      chat_id: entrada.chat_id || null,
      nombre: entrada.nombre || '',
      asunto: entrada.asunto || analisis.funcion_detectada || 'Informe generado',
      mensaje: entrada.mensaje || '',
      tipo_documento: entrada.tipo_documento || analisis.tipo_documento || '',

      // Datos devueltos por la IA
      entidad_contexto: analisis.entidad_contexto || '',
      funcion_detectada: analisis.funcion_detectada || '',
      motivo_clasificacion: analisis.motivo_clasificacion || '',
      hallazgo_condicion: analisis.hallazgo_condicion || '',
      hallazgo_criterio: analisis.hallazgo_criterio || '',
      hallazgo_efecto: analisis.hallazgo_efecto || '',
      hallazgo_causa: analisis.hallazgo_causa || '',
      recomendacion: analisis.recomendacion || '',
      resumen_ejecutivo: analisis.resumen_ejecutivo || '',

      // Por si luego quieres reutilizar el JSON completo
      analisis_json: analisis
    }
  }
];

const crypto = require('crypto');

const item = items[0].json;

// Fecha actual
const now = new Date();
const pad = (n) => String(n).padStart(2, '0');

const fecha = `${now.getFullYear()}-${pad(now.getMonth() + 1)}-${pad(now.getDate())}`;
const hora = `${pad(now.getHours())}:${pad(now.getMinutes())}:${pad(now.getSeconds())}`;

// Registro base que vas a certificar
const registro = {
  chat_id: item.chat_id || '',
  nombre_archivo: item.file_name || '',
  tipo_documento: item.tipo_documento || '',
  funcion_elegida: item.funcion_elegida || '',
  entidad_contexto: item.entidad_contexto || '',
  hallazgo_condicion: item.hallazgo_condicion || '',
  hallazgo_criterio: item.hallazgo_criterio || '',
  hallazgo_efecto: item.hallazgo_efecto || '',
  hallazgo_causa: item.hallazgo_causa || '',
  recomendacion: item.recomendacion || '',
  resumen_ejecutivo: item.resumen_ejecutivo || '',
  fecha_analisis: now.toISOString()
};

// Convertimos a string estable
const registroString = JSON.stringify(registro);

// Hash SHA-256
const hash = crypto.createHash('sha256').update(registroString).digest('hex');

// ID del registro blockchain
const row = item.row_number || Math.floor(Math.random() * 10000);
const blockchain_registro_id = `REG-${fecha.replace(/-/g, '')}-${row}`;

return [
  {
    json: {
      ...item,

      blockchain_payload: registro,
      blockchain_payload_string: registroString,
      blockchain_hash: hash,

      blockchain_registro_id,
      blockchain_fecha: fecha,
      blockchain_hora: hora,
      blockchain_estado: 'registrado'
    }
  }
];
